import React, { useState, useRef } from "react";
console.log("App loaded");
// ── Constants ─────────────────────────────────────────────────────────

const NAV_LINKS = ["Home", "About", "Visualization", "Prediction"];

const AQI_CATEGORIES = [
  { label: "Good",        range: "0–30",    bg: "#16a34a", desc: "Air quality is satisfactory, and air pollution poses little or no risk." },
  { label: "Satisfactory",range: "31–60",   bg: "#ca8a04", desc: "Air quality is acceptable. However, there may be a risk for some people." },
  { label: "Moderate",    range: "61–90",   bg: "#ea580c", desc: "Members of sensitive groups may experience health effects." },
  { label: "Poor",        range: "91–120",  bg: "#dc2626", desc: "The risk of health effects is increased for everyone." },
  { label: "Very Poor",   range: "121–250", bg: "#9333ea", desc: "Health warning: everyone is more likely to be affected." },
  { label: "Severe",      range: "250+",    bg: "#9f1239", desc: "Health alert: Everyone may experience serious health effects." },
];

const MODELS = [
  { name: "🏆 Random Forest",  r2: 0.5183, rmse: 3.6039, mae: 0.3391, time: 63.35,  best: true },
  { name: "Decision Tree",     r2: 0.4348, rmse: 3.9038, mae: 0.3417, time: 1.0 },
  { name: "KNN",               r2: 0.3730, rmse: 4.1116, mae: 0.3607, time: 21.88 },
  { name: "Gradient Boosting", r2: 0.2334, rmse: 4.5465, mae: 0.6754, time: 94.3 },
  { name: "Linear Regression", r2: 0.0097, rmse: 5.1673, mae: 0.7153, time: 0.17 },
];

const TECH_STACK = [
  { icon: "🐍", name: "Python",       desc: "Core Programming Language" },
  { icon: "⚗️", name: "Flask",        desc: "Web Framework" },
  { icon: "🔬", name: "Scikit-learn", desc: "Machine Learning" },
  { icon: "🐼", name: "Pandas",       desc: "Data Processing" },
  { icon: "📊", name: "Chart.js",     desc: "Data Visualization" },
  { icon: "⚛️", name: "React",        desc: "Frontend UI" },
];

const SAMPLE_DATA = [
  { state: "Andhra Pradesh",    so2: 7.2,  no2: 21.5, pm25: 31.0 },
  { state: "Arunachal Pradesh", so2: 4.4,  no2: 9.9,  pm25: 32.0 },
  { state: "Assam",             so2: 18.9, no2: 31.2, pm25: 31.0 },
  { state: "Bihar",             so2: 5.2,  no2: 35.4, pm25: 31.0 },
  { state: "Chandigarh",        so2: 13.0, no2: 24.5, pm25: 19.0 },
  { state: "Delhi",             so2: 9.4,  no2: 31.2, pm25: 51.0 },
  { state: "Goa",               so2: 7.1,  no2: 14.3, pm25: 29.0 },
  { state: "Gujarat",           so2: 11.8, no2: 27.6, pm25: 38.5 },
  { state: "Maharashtra",       so2: 9.3,  no2: 29.1, pm25: 34.2 },
  { state: "Rajasthan",         so2: 8.7,  no2: 22.4, pm25: 42.1 },
];

const STAT_CARDS = [
  { label: "SO2 Average (µg/m³)",  value: "10.60", max: "Max: 909.00", color: "#ef4444", icon: "💨" },
  { label: "NO2 Average (µg/m³)",  value: "25.67", max: "Max: 876.00", color: "#14b8a6", icon: "🌬️" },
  { label: "PM2.5 Average (µg/m³)",value: "32.19", max: "Max: 504.00", color: "#3b82f6", icon: "☁️" },
];

const STATES_LIST = [
  "Andhra Pradesh","Arunachal Pradesh","Assam","Bihar","Chandigarh",
  "Chhattisgarh","Delhi","Goa","Gujarat","Haryana","Himachal Pradesh",
  "Jharkhand","Karnataka","Kerala","Madhya Pradesh","Maharashtra",
  "Manipur","Meghalaya","Mizoram","Nagaland","Odisha","Punjab",
  "Rajasthan","Sikkim","Tamil Nadu","Telangana","Tripura",
  "Uttar Pradesh","Uttarakhand","West Bengal",
];

// ── Helpers ───────────────────────────────────────────────────────────

function getAQICategory(pm25) {
  if (pm25 <= 30)  return AQI_CATEGORIES[0];
  if (pm25 <= 60)  return AQI_CATEGORIES[1];
  if (pm25 <= 90)  return AQI_CATEGORIES[2];
  if (pm25 <= 120) return AQI_CATEGORIES[3];
  if (pm25 <= 250) return AQI_CATEGORIES[4];
  return AQI_CATEGORIES[5];
}

function mockPredict({ so2, no2, rspm, spm }) {
  const base = 0.15 * so2 + 0.22 * no2 + 0.08 * rspm + 0.04 * spm + 8.5;
  return Math.max(0, base + (Math.random() - 0.5) * 3);
}

