// ── Bar Chart (SVG) ───────────────────────────────────────────────────

function BarChart({ data }) {
  const maxVal = Math.max(...data.map((d) => Math.max(d.so2, d.no2, d.pm25)));
  const chartH  = 220;
  const barW    = 14;
  const gap     = 4;
  const groupW  = barW * 3 + gap * 2 + 22;

  return (
    <div style={{ overflowX: "auto" }}>
      <svg width={data.length * groupW + 60} height={chartH + 80} style={{ display: "block" }}>
        {[0, 20, 40, 60].map((v) => (
          <g key={v}>
            <line
              x1={40} x2={data.length * groupW + 50}
              y1={chartH - (v / maxVal) * chartH + 10}
              y2={chartH - (v / maxVal) * chartH + 10}
              stroke="#e2e8f0" strokeWidth={1}
            />
            <text
              x={36} y={chartH - (v / maxVal) * chartH + 14}
              textAnchor="end" fontSize={11} fill="#94a3b8"
            >{v}</text>
          </g>
        ))}
        {data.map((d, i) => {
          const x = i * groupW + 50;
          return (
            <g key={d.state}>
              {[["so2", "#f87171"], ["no2", "#2dd4bf"], ["pm25", "#60a5fa"]].map(([key, color], j) => {
                const h = (d[key] / maxVal) * chartH;
                return (
                  <rect
                    key={key}
                    x={x + j * (barW + gap)} y={chartH - h + 10}
                    width={barW} height={h}
                    fill={color} rx={2} opacity={0.85}
                  />
                );
              })}
              <text
                x={x + barW * 1.5 + gap} y={chartH + 30}
                textAnchor="middle" fontSize={10} fill="#64748b"
                transform={`rotate(-35, ${x + barW * 1.5 + gap}, ${chartH + 30})`}
              >
                {d.state.length > 10 ? d.state.slice(0, 10) + "…" : d.state}
              </text>
            </g>
          );
        })}
        {[["SO2", "#f87171"], ["NO2", "#2dd4bf"], ["PM2.5", "#60a5fa"]].map(([label, color], i) => (
          <g key={label} transform={`translate(${50 + i * 80}, ${chartH + 60})`}>
            <rect width={12} height={12} fill={color} rx={2} />
            <text x={16} y={11} fontSize={11} fill="#64748b">{label}</text>
          </g>
        ))}
      </svg>
    </div>
  );
}

// ── Visualization Page ────────────────────────────────────────────────

function VisualizationPage() {
  const [tableData, setTableData] = useState(SAMPLE_DATA);
  const [fileNames, setFileNames]   = useState([]);
  const fileRef = useRef();

  function handleFileUpload(e) {
    const files = Array.from(e.target.files);
    setFileNames(files.map((f) => f.name));
    files.forEach((file) => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const lines   = ev.target.result.split("\n").filter(Boolean);
        const headers = lines[0].split(",").map((h) => h.trim().toLowerCase());
        const parsed  = lines.slice(1).map((line) => {
          const cols = line.split(",");
          const row  = {};
          headers.forEach((h, i) => { row[h] = cols[i]?.trim(); });
          return row;
        }).filter((r) => r.state);
        if (parsed.length > 0) {
          setTableData((prev) => [...prev, ...parsed.slice(0, 5)]);
        }
      };
      reader.readAsText(file);
    });
  }

  return (
    <div style={{ background: "#f8fafc", minHeight: "100vh" }}>
      {/* Header */}
      <div style={{
        background: "linear-gradient(135deg, #1a2e40 0%, #0f4c75 100%)",
        padding: "3rem 2rem", textAlign: "center", color: "#fff",
