          <div style={{ fontSize: 32, marginBottom: 8 }}>📂</div>
          <p style={{ color: "#475569", marginBottom: 12 }}>Upload your CSV location files</p>
          <input
            ref={fileRef} type="file" accept=".csv" multiple
            onChange={handleFileUpload} style={{ display: "none" }}
          />
          <button
            onClick={() => fileRef.current.click()}
            style={{
              background: "#2dd4bf", color: "#0f2027", border: "none",
              padding: "10px 24px", borderRadius: 8, fontWeight: 700, cursor: "pointer",
            }}
          >
