// ── Prediction Page ───────────────────────────────────────────────────
function PredictionPage() {
  const [inputs, setInputs] = useState({
    state: "Andhra Pradesh",
    co: "", PS: "", THI: "", RH2M: "",
    temperature: "", relativehumidity: "",
    o3: "", wind_speed: "", AOD: "", T2M: "",
  });

  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState([]);

  function handleChange(key, value) {
    setInputs((prev) => ({ ...prev, [key]: value }));
  }

  async function handlePredict() {
    const values = Object.values(inputs).slice(1); // ignore state

    if (values.some(v => v === "")) {
      alert("Please fill all fields");
      return;
    }

    setLoading(true);

    try {
      const response = await fetch("http://127.0.0.1:5000/predict", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          location: inputs.state.toLowerCase(),
          co: +inputs.co,
          PS: +inputs.PS,
          THI: +inputs.THI,
          RH2M: +inputs.RH2M,
          temperature: +inputs.temperature,
          relativehumidity: +inputs.relativehumidity,
          o3: +inputs.o3,
          wind_speed: +inputs.wind_speed,
          AOD: +inputs.AOD,
          T2M: +inputs.T2M
        })
      });

      const data = await response.json();

      if (data.error) {
        alert(data.error);
        setLoading(false);
        return;
      }

      const pm25Val = data.pm25;
      const cat = getAQICategory(pm25Val);

      const newResult = {
        pm25: pm25Val.toFixed(2),
        cat,
        state: inputs.state,
        ts: new Date().toLocaleTimeString()
      };

      setResult(newResult);
      setHistory((prev) => [newResult, ...prev].slice(0, 5));

    } catch (err) {
      console.error(err);
      alert("Error connecting to backend");
    }

    setLoading(false);
  }

  const isDisabled = loading;

  function InputField({ label, fieldKey, placeholder }) {
    return (
      <div style={{ marginBottom: "1.25rem" }}>
        <label style={{
          display: "flex", justifyContent: "space-between",
          marginBottom: 6, fontSize: 14, fontWeight: 600, color: "#334155",
        }}>
          <span>{label}</span>
        </label>
        <input
          type="number"
          placeholder={placeholder}
          value={inputs[fieldKey]}
          onChange={(e) => handleChange(fieldKey, e.target.value)}
          style={{
            width: "100%", padding: "10px 14px", borderRadius: 8,
            border: "1.5px solid #e2e8f0", fontSize: 15
          }}
        />
      </div>
    );
  }

  return (
    <div style={{ background: "#f8fafc", minHeight: "100vh", padding: "2rem" }}>
      <div style={{ maxWidth: 1100, margin: "0 auto" }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "2rem" }}>

          {/* INPUT PANEL */}
          <div style={{ background: "#fff", borderRadius: 14, padding: "2rem", border: "1px solid #e2e8f0" }}>
            <h2>🧮 Input Parameters</h2>

            <InputField label=" 🟤 CO" fieldKey="co" placeholder="0.5" />
            <InputField label="🌡️ Pressure (PS)" fieldKey="PS" placeholder="1010" />
            <InputField label="🔥THI" fieldKey="THI" placeholder="25" />
            <InputField label="💧 RH2M" fieldKey="RH2M" placeholder="60" />
            <InputField label="🌡️Temperature" fieldKey="temperature" placeholder="30" />
            <InputField label="💦  Humidity" fieldKey="relativehumidity" placeholder="70" />
            <InputField label="🌿O3" fieldKey="o3" placeholder="20" />
            <InputField label="🌬️Wind Speed" fieldKey="wind_speed" placeholder="3" />
            <InputField label="☁️AOD" fieldKey="AOD" placeholder="0.5" />
            <InputField label="🌡️T2M" fieldKey="T2M" placeholder="300" />

            {/* State */}
            <select
              value={inputs.state}
              onChange={(e) => handleChange("state", e.target.value)}
              style={{ marginBottom: "1rem", padding: "10px", width: "100%" }}
            >
              {STATES_LIST.map((s) => <option key={s}>{s}</option>)}
            </select>

            <button
              onClick={handlePredict}
              disabled={isDisabled}
              style={{
                width: "100%", padding: 14, borderRadius: 10,
                background: isDisabled ? "#e2e8f0" : "#1a2e40",
                color: "#fff", fontWeight: 700
              }}
            >
              {loading ? "⏳ Predicting..." : "🔮 Predict PM2.5"}
            </button>
          </div>

          {/* RESULT PANEL */}
          <div style={{ background: "#fff", borderRadius: 14, padding: "2rem", border: "1px solid #e2e8f0" }}>
            <h2>📊 Result</h2>

            {result ? (
              <>
                <h1>{result.pm25} µg/m³</h1>
                <h2 style={{ color: result.cat.bg }}>{result.cat.label}</h2>
                <p>{result.cat.desc}</p>
              </>
            ) : (
              <p>No prediction yet</p>
            )}

            {/* History */}
            {history.map((h, i) => (
              <p key={i}>{h.pm25} - {h.state}</p>
            ))}
          </div>

        </div>
      </div>
    </div>
  );
}

function AirQuality() {
  const [page, setPage] = useState("Home");

  return (
    <div style={{ fontFamily: "'Segoe UI', system-ui, sans-serif", minHeight: "100vh", background: "#f8fafc" }}>
      <Navbar page={page} setPage={setPage} />
      {page === "Home"          && <HomePage setPage={setPage} />}
      {page === "About"         && <AboutPage />}
      {page === "Visualization" && <VisualizationPage />}
      {page === "Prediction"    && <PredictionPage />}
      <Footer setPage={setPage} />
    </div>
  );
}

export default AirQuality;
